<?php $rows=getStaff(); ?><section class="card"><h2>Личный состав</h2><div class="gallery-grid"><?php foreach($rows as $r): ?><article class="tile"><?php if($r['photo']): ?><img src="<?= e($r['photo']) ?>" alt="<?= e($r['full_name']) ?>"><?php endif; ?><div><strong><?= e($r['full_name']) ?></strong><p class="muted small"><?= e($r['position']) ?></p></div></article><?php endforeach; ?></div></section>